sql:
SELECT s.song_title, a.artist_name
FROM songs s
INNER JOIN artists a ON s.artist_id = a.artist_id;

SELECT AVG(rating) 
FROM song_ratings 
WHERE song_id = (SELECT song_id FROM songs WHERE song_title = 'Song_Z');

external_knowledge:
- 'top artists' refers to the artists with the highest number of followers; 
- 'largest crowd' indicates those with the most fans; 
- 'most popular tunes' are the songs with the highest view counts; 
- 'often listened to' means the songs that have the highest number of views in the dataset.

sql:
SELECT DISTINCT a.artist_name, a.artist_id
FROM artists AS a
JOIN songs AS s ON a.artist_id = s.artist_id;

SELECT songs.song_title, albums.album_title
FROM songs
JOIN albums ON songs.album_id = albums.album_id;
